def parse_min(text):
    """将 westock minute text 解析为 5min 聚合 bars: [{time, open, high, low, close, vol, amount}]"""
    lines = [l for l in text.split("\n") if l.strip()]
    parsed = []
    for l in lines:
        parts = l.split()
        if len(parts) < 4:
            continue
        t = parts[0]
        if not re.match(r"^\d{4}$", t):
            continue
        price = float(parts[1])
        vol = float(parts[2])
        amt = float(parts[3]) if len(parts) > 3 else 0
        h = int(t[:2])
        m = int(t[2:])
        parsed.append((h * 60 + m, price, price, price, price, vol, amt))
    if not parsed:
        return []
    # 5min 聚合
    bars = []
    cur = None
    for tm, p, _, _, _, v, a in parsed:
        bucket = (tm // 5) * 5
        if cur is None or cur["minutes"] != bucket:
            if cur:
                bars.append(cur)
            cur = {"minutes": bucket, "open": p, "high": p, "low": p, "close": p, "vol": v, "amount": a}
        else:
            cur["high"] = max(cur["high"], p)
            cur["low"] = min(cur["low"], p)
            cur["close"] = p
            cur["vol"] += v
            cur["amount"] += a
    if cur:
        bars.append(cur)
    for b in bars:
        h, m = divmod(b["minutes"], 60)
        b["time"] = "%02d:%02d" % (h, m)
    return bars


out = {"date": "2026-07-14", "indices": {}}
for code, rec in DATA.items():
    bars = parse_min(rec["data"])
    if bars:
        out["indices"][code] = {"name": rec["name"], "code": code, "bars": bars}
        print(f"OK {code} {rec['name']:8s} {len(bars)} bars | first={bars[0]} | last={bars[-1]}")
    else:
        print(f"SKIP {code} {rec['name']}")

os.makedirs(os.path.dirname(os.path.abspath('data/market_intraday_2026-07-14.json')), exist_ok=True)
out_path = "data/market_intraday_2026-07-14.json"
with open(out_path, "w", encoding="utf-8") as f:
    json.dump(out, f, ensure_ascii=False, indent=1)
print("saved", out_path, "size", os.path.getsize(out_path))
